const phone = $json.waId || $json.from;
const name  = $json.senderName || 'Friend';
return [{ json: {
  phone,
  confirmMsg: `✅ *Subscribed, ${name}!*

You'll get your daily briefing every morning at 7AM.

Send *brief* anytime for an instant update.
Send *stop* to unsubscribe.`
}}];

const phone = $json.waId || $json.from;
const name  = $json.senderName || 'Friend';
return [{ json: {
  phone,
  confirmMsg: `👋 *Unsubscribed, ${name}.*

No more daily briefings from us.
Send *subscribe* anytime to rejoin!`
}}];

// ── Called from TWO entry points ─────────────────────────────────────
// 1) Schedule path → $json has no waId; use the subscriber list below
// 2) On-demand path → $json.waId is set; build a single-user object

const isOnDemand = '917024935915'|| $json.from;

if (isOnDemand) {
  return [{ json: {
    phone:     '917024935915' || $json.from,
    name:      $json.senderName || 'Friend',
    city:      'Mumbai',           // default city for on-demand
    interests: 'technology,business',
    source:    'on-demand'
  }}];
}

// ── Edit this list to add/remove subscribers ──────────────────────────
const subscribers = [
  { phone: 'SUBSCRIBER_PHONE_1', name: 'Priya',  city: 'Mumbai',    interests: 'technology,startups' },
  { phone: 'SUBSCRIBER_PHONE_2', name: 'Arjun',  city: 'Bengaluru', interests: 'finance,business'   },
  { phone: 'SUBSCRIBER_PHONE_3', name: 'Sneha',  city: 'Delhi',     interests: 'health,science'     }
];

return subscribers.map(s => ({ json: { ...s, source: 'schedule' } }));

// ── Collect from all upstream nodes ──────────────────────────────────
const sub = $('Load User Config').item.json;

// Weather
let weatherLine = '🌤️ Weather unavailable';
let weatherEmoji = '☀️';
try {
  const w    = $('Fetch Weather').item.json;
  const temp = Math.round(w.main?.temp || 0);
  const feel = Math.round(w.main?.feels_like || 0);
  const desc = (w.weather?.[0]?.description || 'clear').replace(/\b\w/g, c => c.toUpperCase());
  const hum  = w.main?.humidity || 0;
  const wind = Math.round((w.wind?.speed || 0) * 3.6);
  const city = w.name || sub.city;
  const iconMap = { clear:'☀️', cloud:'⛅', rain:'🌧️', storm:'⛈️', snow:'❄️', mist:'🌫️', fog:'🌫️' };
  const icon = iconMap[Object.keys(iconMap).find(k => desc.toLowerCase().includes(k)) || 'cloud'] || '🌤️';
  weatherEmoji = icon;
  weatherLine  = `${icon} *${city}* — ${temp}°C (feels ${feel}°C) · ${desc}\n  💧 Humidity ${hum}% · 💨 Wind ${wind} km/h`;
} catch(e) {}

// News
let newsLines = ['  No headlines available'];
try {
  const arts = $('Fetch News').item.json.articles || [];
  if (arts.length > 0) {
    newsLines = arts.slice(0, 3).map((a, i) =>
      `  ${i+1}. ${a.title}\n     _${a.source?.name || 'Source'}_`
    );
  }
} catch(e) {}

// Calendar
let calLines   = ['  🎉 No events today'];
let eventCount = 0;
try {
  const events = $('Get Today’s Calendar Events').all().map(r => r.json);
  if (events.length > 0) {
    eventCount = events.length;
    calLines = events
      .filter(e => e.start)
      .sort((a, b) => new Date(a.start.dateTime || a.start.date) - new Date(b.start.dateTime || b.start.date))
      .slice(0, 5)
      .map(e => {
        let time = '';
        if (e.start?.dateTime) {
          time = new Date(e.start.dateTime).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: false }) + ' · ';
        }
        return `  ${time}${e.summary || 'Untitled event'}`;
      });
  }
} catch(e) {}

// Tasks
let taskLines = ['  ✅ All clear for today'];
let taskCount = 0;
try {
  const tasks = $('Get Due Tasks').all().map(r => r.json).filter(t => t.title && t.status !== 'completed');
  if (tasks.length > 0) {
    taskCount = tasks.length;
    taskLines = tasks.slice(0, 5).map(t => `  • ${t.title}`);
  }
} catch(e) {}

// AI opener
const rawOpener = $json?.choices?.[0]?.message?.content || '';
const opener = rawOpener.trim() || `Have a productive ${new Date().toLocaleDateString('en-IN', { weekday: 'long' })}, ${sub.name}!`;

// Build message
const now      = new Date();
const dayStr   = now.toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'short' });
const greet    = now.getHours() < 12 ? 'Good morning' : now.getHours() < 17 ? 'Good afternoon' : 'Good evening';
const calHead  = `📅 *Your Day*${eventCount > 0 ? '  (' + eventCount + ' event' + (eventCount > 1 ? 's' : '') + ')' : ''}`;
const taskHead = `✅ *Priority Tasks*${taskCount > 0 ? '  (' + taskCount + ' due today)' : ''}`;

const msg = [
  `${weatherEmoji} *${greet}, ${sub.name}!*  ${dayStr}`,
  '',
  `💬 _${opener}_`,
  '',
  `🌤️ *Weather*`,
  weatherLine,
  '',
  `📰 *Top Headlines*`,
  ...newsLines,
  '',
  calHead,
  ...calLines,
  '',
  taskHead,
  ...taskLines,
  '',
  '─────────────────',
  '_Reply *brief* anytime for a refresh_'
].join('\n');

return [{ json: { phone: sub.phone, briefing: msg } }];
